pub fn refineAdjacency(kind: TokenKind, prev_kind: TokenKind, text: []const u8) TokenKind {
    if (kind == .plain and (prev_kind == .user_prompt or prev_kind == .user_text)) {
        return .user_text;
    }
    if (kind == .plain or kind == .menu_option) {
        if (prev_kind == .tool or prev_kind == .thinking or prev_kind == .thought_complete or prev_kind == .result or prev_kind == .assistant_text or prev_kind == .task_done or prev_kind == .task_open or prev_kind == .task_summary or prev_kind == .task_active or prev_kind == .diff or prev_kind == .plan_border) {
            return .assistant_text;
        }
    }
    if (kind == .plain and prev_kind == .menu_option) {
        return .menu_desc;
    }
    if (kind == .plain) {
        if (contains(text, "Enter to select") or contains(text, "Arrow keys") or contains(text, "Esc to cancel") or contains(text, "Esc to go back") or contains(text, "Type to search") or (contains(text, "Ctrl+") and contains(text, " to "))) {
            return .hint;
        }
    }
    return kind;
}

pub fn isTurnStartBasic(kind: TokenKind) bool {
    return kind == .command;
}

pub fn isTurnStartClaude(kind: TokenKind) bool {
    return kind == .user_prompt;
}

pub fn setClassifier(ct: ClassifierType) void {
    g_classifier = ct;
    g_prev_kind = .plain;
}

pub fn classifyRow(text: []const u8, row: u16, total_rows: u16) u8 {
    const raw_kind = switch (g_classifier) { .basic => classifyBasic(text, row, total_rows), .claude_code => classifyClaude(text, row, total_rows) };
    const kind = if (g_classifier == .claude_code) refineAdjacency(raw_kind, g_prev_kind, text) else raw_kind;
    g_prev_kind = kind;
    return @intFromEnum(kind);
}

pub fn resetClassifier() void {
    g_prev_kind = .plain;
}

